long long solve(std::string s, std::vector<long long> order, long long k) {
    int n = s.length();
    std::vector<bool> replaced(n, false);
    std::vector<int> positions(n);

    // Record the positions of each character in the order
    for (int i = 0; i < n; ++i) {
        positions[order[i]] = i;
    }

    long long total = 0;
    long long result = -1;

    for (int t = 0; t < n; ++t) {
        int pos = order[t];
        replaced[pos] = true;

        // Calculate the number of valid substrings after this replacement
