        int right = pos;
        while (left >= 0 && replaced[left]) {
            left--;
        }
        while (right < n && replaced[right]) {
            right++;
        }

        int left_count = pos - left;
        int right_count = right - pos;
        total += left_count * right_count;

        if (total >= k) {
            result = t;
            break;
        }
    }

    return result;
}

